parameters.text:
=Extract event information from this RSS feed item:

Title: {{ $json.title }}
Content: {{ $json.content || $json.summary || $json.description }}
Link: {{ $json.link }}
Published: {{ $json.pubDate || $json.isoDate }}

Return ONLY this exact JSON:
{
  "event_title": "Full event title here",
  "event_date": "YYYY-MM-DD or date string",
  "location": "City, Country or Online",
  "description": "2-3 sentence summary",
  "event_url": "https://event-url.com",
  "event_type": "Summit|Webinar|Workshop|Conference|Other",
  "is_upcoming": true,
  "relevance_score": 85
}

parameters.jsCode:
const item = $input.first();
const original = $('Loop Over Items').first().json;

// Generate unique message ID from RSS item
const messageId = 'MSG-' + 
  (original.guid || original.link || Date.now())
  .toString()
  .replace(/[^a-zA-Z0-9]/g, '')
  .substring(0, 10);

// Get AI output
let rawOutput = item.json.output || '';
let eventData = {};

try {
  if (typeof rawOutput === 'string') {
    rawOutput = rawOutput
      .replace(/```json/gi, '')
      .replace(/```/g, '')
      .trim();

    const start = rawOutput.indexOf('{');
    const end = rawOutput.lastIndexOf('}');

    if (start !== -1 && end !== -1) {
      eventData = JSON.parse(
        rawOutput.substring(start, end + 1)
      );
    }
  } else if (typeof rawOutput === 'object') {
    eventData = rawOutput;
  }
} catch(e) {
  // Safe fallback using RSS data directly
  eventData = {
    event_title: original.title || 'Unknown Event',
    event_date: original.pubDate || 
                new Date().toISOString(),
    location: 'Online',
    description: original.summary || 
                 original.content || '',
    event_url: original.link || '',
    event_type: 'Other',
    is_upcoming: true,
    relevance_score: 50
  };
}

// Validate required fields
if (!eventData.event_title) {
  return [{
    json: {
      error: true,
      message: 'No event title extracted',
      message_id: messageId,
      skip: true
    }
  }];
}

// Normalize event URL
let eventUrl = (eventData.event_url || 
                original.link || '').trim();
if (eventUrl && !eventUrl.startsWith('https://')) {
  eventUrl = 'https://' + eventUrl;
}

// Normalize event type
const validTypes = [
  'Summit', 'Webinar', 'Workshop',
  'Conference', 'Other'
];
let eventType = (eventData.event_type || 'Other')
  .trim();
if (!validTypes.includes(eventType)) {
  eventType = 'Other';
}

// Normalize relevance score
let score = parseInt(eventData.relevance_score) || 50;
if (score > 100) score = 100;
if (score < 0) score = 0;

// Clean description
const description = (eventData.description || '')
  .substring(0, 500)
  .replace(/\n+/g, ' ')
  .trim();

return [{
  json: {
    message_id: messageId,
    event_title: eventData.event_title
      .substring(0, 200),
    event_date: eventData.event_date || 'TBD',
    location: eventData.location || 'Online',
    description: description,
    event_url: eventUrl,
    event_type: eventType,
    is_upcoming: eventData.is_upcoming !== false,
    relevance_score: score,
    source_feed: original.link || '',
    error: false,
    skip: false,
    processed_at: new Date().toISOString()
  }
}];
